my @find_files_3; sub find_files_3 { my ($dir, $pattern) = @_; if (opendir(my $dh, $dir)) { while (my $file = readdir($dh)) { next if $file eq "." || $file eq ".."; my $full_path = $dir eq "." ? "./$file" : "$dir/$file"; if (-d $full_path) { find_files_3($full_path, $pattern); } elsif ($file =~ /^$pattern$/) { push @find_files_3, $full_path; } } closedir($dh); } } find_files_3(".", ".*\\.sh"); print "Found files:\n"; print join("\n", @find_files_3), "\n"; print "Count: " . scalar(@find_files_3) . "\n";
